SELECT task_id, AVG(session_duration) AS average_session_duration
FROM collaborative_sessions
GROUP BY task_id;

SELECT group_id, COUNT(session_id) AS total_sessions
FROM collaborative_sessions
GROUP BY group_id;

SELECT AVG(group_count) AS average_group_count
FROM (
    SELECT ug.user_id, COUNT(ug.group_id) AS group_count
    FROM user_groups ug
    GROUP BY ug.user_id
) AS subquery;

SELECT user_id, COUNT(feedback_id) AS total_feedbacks
FROM session_feedback
GROUP BY user_id;

SELECT users.user_id, users.user_name, user_badges.badge_name
FROM users
JOIN user_badges ON users.user_id = user_badges.user_id;

SELECT user_id, task_id, difficulty_rating,
       RANK() OVER (PARTITION BY user_id ORDER BY difficulty_rating DESC) AS user_rating_rank
FROM task_ratings;

SELECT session_id, AVG(comfort) AS average_comfort
FROM collaborative_sessions
GROUP BY session_id;
